	assert.Equal(t, local.Title, beadEnv.Data.Title)
	require.Len(t, beadEnv.Data.Dependencies, 1)
	assert.Equal(t, local.Dependencies[0].DependsOnID, beadEnv.Data.Dependencies[0].DependsOnID)

