			return s.writeClaimHeartbeat(ClaimLeaseRecord{
				BeadID:    id,
				Owner:     assignee,
				Session:   session,
				Worktree:  worktree,
				Machine:   machine,
				StartedAt: now,
				UpdatedAt: now,
				PID:       os.Getpid(),
			})
		}
		return fmt.Errorf("bead: not found: %s", id)
	})

