package bead

import (
	"context"
	"encoding/json"
	"fmt"
	"io"
	"os"
	"os/exec"
	"path/filepath"
	"strings"
)

// Import reads beads from an external source and merges them into the store.
// Returns the number of beads imported.
func (s *Store) Import(ctx context.Context, source, filePath string) (int, error) {
	if err := ctx.Err(); err != nil {
		return 0, err
	}
	if source == "" || source == "auto" {
		return s.importAuto(filePath)
	}

	switch source {
	case "bd":
		return s.importFromTool("bd")
	case "br":
		return s.importFromTool("br")
	case "jsonl":
		return s.importFromJSONL(filePath)
	default:
		return 0, fmt.Errorf("bead: unknown import source: %s", source)
	}
}

// ExportTo writes all beads as JSONL to the given writer.
//
// For interchange compatibility with bd/br, externalized event histories are
// inlined back into the row's "events" array on the way out (the attachment
// ref itself is also dropped so importers don't see a dangling pointer).
// The on-disk row is unchanged — this is a transient mutation on the copied
// Bead value before marshaling.
//
// When called on the active collection, archived beads from the
// beads-archive partner are also streamed inline so a single export carries
// the full corpus. Each archived bead's externalized events are loaded from
// the active store's attachment dir (where Migrate writes them) before
// emission.
func (s *Store) ExportTo(ctx context.Context, w io.Writer) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	beads, err := s.ReadAll(ctx)
	if err != nil {
		return err
	}
	seen := make(map[string]bool, len(beads))
	for _, b := range beads {
		seen[b.ID] = true
		if hasEventsAttachment(&b) {
			if err := s.inlineEventsInPlace(&b); err != nil {
				return fmt.Errorf("bead: export inline events: %w", err)
			}
		}
		data, err := marshalBead(b)
		if err != nil {
			return fmt.Errorf("bead: export marshal: %w", err)
		}
		if _, err := fmt.Fprintf(w, "%s\n", data); err != nil {
			return fmt.Errorf("bead: export write: %w", err)
		}
	}

	if s.Collection != DefaultCollection {
		return nil
	}
	archive := s.archivePartner()
	archived, aerr := archive.ReadAll(ctx)
	if aerr != nil {
		// Treat a missing/unreadable archive partner as empty — the
		// active collection is still a valid export.
		return nil
	}
	for _, b := range archived {
		if seen[b.ID] {
			continue
		}
		if hasEventsAttachment(&b) {
			// Attachments live under the active store's .ddx/attachments
			// dir even after the bead moves to the archive (Migrate
			// writes them there before archival). Use s, not archive,
			// to resolve the sidecar path.
			if err := s.inlineEventsInPlace(&b); err != nil {
				return fmt.Errorf("bead: export inline events: %w", err)
			}
		}
		data, err := marshalBead(b)
		if err != nil {
			return fmt.Errorf("bead: export marshal: %w", err)
		}
		if _, err := fmt.Fprintf(w, "%s\n", data); err != nil {
			return fmt.Errorf("bead: export write: %w", err)
		}
	}
	return nil
}

// ExportToFile writes all beads as JSONL to the given file path.
func (s *Store) ExportToFile(ctx context.Context, filePath string) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	dir := filepath.Dir(filePath)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("bead: export mkdir: %w", err)
	}
	f, err := os.Create(filePath)
	if err != nil {
		return fmt.Errorf("bead: export create: %w", err)
	}
	defer f.Close()
	return s.ExportTo(ctx, f)
}

// migrateFromHelix checks for .helix/issues.jsonl and imports beads into the
// DDx store if it exists and the DDx store is empty. Returns (count, migrated, error).
func (s *Store) migrateFromHelix() (int, bool, error) {
	helixFile := ".helix/issues.jsonl"
	if _, err := os.Stat(helixFile); err != nil {
		return 0, false, nil // no HELIX tracker, nothing to do
	}

	// Check if DDx store already has beads
	existing, err := s.ReadAll(context.Background())
	if err == nil && len(existing) > 0 {
		return 0, false, nil // DDx store already populated
	}

	n, err := s.importFromJSONL(helixFile)
	if err != nil {
		return 0, false, fmt.Errorf("bead: migrate from .helix/issues.jsonl: %w", err)
	}
	return n, n > 0, nil
}

func (s *Store) importAuto(filePath string) (int, error) {
	// Try bd
	if _, err := exec.LookPath("bd"); err == nil {
		n, err := s.importFromTool("bd")
		if err == nil && n > 0 {
			return n, nil
		}
	}

	// Try br
	if _, err := exec.LookPath("br"); err == nil {
		n, err := s.importFromTool("br")
		if err == nil && n > 0 {
			return n, nil
		}
	}

	// Try known bead file locations in priority order
	beadsFile := filePath
	if beadsFile == "" {
		for _, candidate := range []string{
			".beads/issues.jsonl", // bd default
			".helix/issues.jsonl", // HELIX legacy tracker
		} {
			if _, err := os.Stat(candidate); err == nil {
				beadsFile = candidate
				break
			}
		}
		if beadsFile == "" {
			beadsFile = ".beads/issues.jsonl" // fallback for error message
		}
	}
	return s.importFromJSONL(beadsFile)
}

func (s *Store) importFromTool(tool string) (int, error) {
	cmd := exec.Command(tool, "list", "--json")
	output, err := cmd.Output()
	if err != nil {
		return 0, fmt.Errorf("bead: %s list --json: %w", tool, err)
	}

	return s.mergeJSONL(string(output))
}

func (s *Store) importFromJSONL(path string) (int, error) {
	data, err := os.ReadFile(path)
	if err != nil {
		return 0, fmt.Errorf("bead: read %s: %w", path, err)
	}
	return s.mergeJSONL(string(data))
}

func (s *Store) mergeJSONL(data string) (int, error) {
	var incoming []Bead
	var parseErrors int

	// Try as JSON array first, then as JSONL
	trimmed := strings.TrimSpace(data)
	if strings.HasPrefix(trimmed, "[") {
		var raw []json.RawMessage
		if err := json.Unmarshal([]byte(trimmed), &raw); err != nil {
			return 0, fmt.Errorf("bead: import parse: %w", err)
		}
		for _, r := range raw {
			b, err := unmarshalBead(r)
			if err != nil {
				parseErrors++
				continue
			}
			incoming = append(incoming, b)
		}
	} else {
		for _, line := range strings.Split(trimmed, "\n") {
			line = strings.TrimSpace(line)
			if line == "" {
				continue
			}
			b, err := unmarshalBead([]byte(line))
			if err != nil {
				parseErrors++
				continue
			}
			incoming = append(incoming, b)
		}
	}

	if parseErrors > 0 && len(incoming) == 0 {
		return 0, fmt.Errorf("bead: import failed: %d malformed record(s), 0 valid", parseErrors)
	}
	if parseErrors > 0 {
		fmt.Fprintf(os.Stderr, "bead: import: skipped %d malformed record(s)\n", parseErrors)
	}

	if len(incoming) == 0 {
		return 0, nil
	}

	return s.mergeBeads(incoming)
}

func (s *Store) mergeBeads(incoming []Bead) (int, error) {
	var count int
	err := s.WithLock(func() error {
		existing, err := s.ReadAll(context.Background())
		if err != nil {
			return err
		}

		existingIDs := make(map[string]bool)
		for _, b := range existing {
			existingIDs[b.ID] = true
		}

	archiveSpec := DefaultRegistry().Resolve(BeadsArchiveCollection)
	archiveFile, archiveLock := archiveSpec.PathsUnder(s.Dir)
	archiveBackend := NewJSONLBackend(s.Dir, archiveFile, archiveLock, s.LockWait)

	activeBeads, err := activeBackend.ReadAll()
	if err != nil {
		return stats, fmt.Errorf("bead: migrate-to-axon read active: %w", err)
	}
	archiveBeads, err := archiveBackend.ReadAll()
	if err != nil {
		return stats, fmt.Errorf("bead: migrate-to-axon read archive: %w", err)
	}

	seen := make(map[string]bool, len(activeBeads))
	merged := make([]Bead, 0, len(activeBeads)+len(archiveBeads))
	for _, b := range activeBeads {
		seen[b.ID] = true
		merged = append(merged, b)
	}
	for _, b := range archiveBeads {
		if seen[b.ID] {
			continue
		}
		seen[b.ID] = true
		merged = append(merged, b)
	}

	for i := range merged {
		stats.BeadsMigrated++
		if hasInlineEvents(&merged[i]) {
			stats.EventsMigrated += len(decodeBeadEvents(merged[i].Extra["events"]))
		}
	}

	axon := NewAxonBackend(s.Dir, s.LockWait)
	if err := axon.Init(); err != nil {
		return stats, fmt.Errorf("bead: migrate-to-axon init: %w", err)
	}
	if err := axon.WithLock(func() error {
		return axon.WriteAll(merged)
	}); err != nil {
		return stats, fmt.Errorf("bead: migrate-to-axon write: %w", err)
	}
	return stats, nil
}

// hasInlineEvents reports whether a bead carries any inline events that
// can still be externalized. An empty array counts as "no inline events"
// so a second migrate pass on an already-externalized bead is a no-op.
func hasInlineEvents(b *Bead) bool {
	if b == nil || b.Extra == nil {
		return false
	}
	raw, ok := b.Extra["events"]
	if !ok {
		return false
	}
	return len(decodeBeadEvents(raw)) > 0
}

func inlineEventCount(b *Bead) int {
	if b == nil || b.Extra == nil {
		return 0
	}
	raw, ok := b.Extra["events"]
	if !ok {
		return 0
	}
	return len(decodeBeadEvents(raw))
}

